export const getGetPredictionDistributionUrl = (params?: GetPredictionDistributionParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/summary/prediction-distribution?${stringifiedParams}` : `/api/summary/prediction-distribution`
}

